#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
const int up = 100000;
const LL MOD = (1ll<<31);
struct query{
    int id;
    LL n,m,a;
}q[N];
bool cmp_q(query q1,query q2){
    return q1.a<q2.a;
}
struct nums{
    int x;LL val;
}s[N];
bool cmp_s(nums s1,nums s2){
    return s1.val<s2.val;
}
LL Q,Ans[N];
LL p[N],cnt;
bool vis[N];//素数筛
LL mu[N],sig[N];
//莫反函数与约数和
LL c[N];//树状数组
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init(){
    vis[0]=1,vis[1]=1,cnt=0;
    mu[1]=1,sig[1]=1;//初始化
    for(LL i=2;i<=up;i++){
        if(!vis[i])p[++cnt]=i,mu[i]=-1,sig[i]=i+1;
        for(LL j=1;j<=cnt&&p[j]*i<=up;j++){
            vis[p[j]*i]=1;
            if(i%p[j]==0){
                sig[i*p[j]]=sig[i]+(sig[i]-sig[i/p[j]]+MOD)%MOD*p[j]%MOD;
                sig[i*p[j]]%=MOD;
                mu[i*p[j]]=0;break;
            }else mu[i*p[j]]=mu[i]*mu[p[j]],
                sig[i*p[j]]=(sig[i]+sig[i]*p[j]%MOD)%MOD;
        }
    }//线性筛并同时算出莫反和约数和两个函数的值
    for(int i=1;i<=up;i++)
        s[i].val=sig[i],s[i].x=i;
    sort(s+1,s+up+1,cmp_s);
    //统计下来并排序
    return;
}
void upd(int x,LL k){while(x<=up)c[x]=(c[x]+k)%MOD,x+=x&-x;return;}
LL ask(int x){LL sum=0;while(x)sum=(sum+c[x])%MOD,x-=x&-x;return sum;}
//树状数组的实现
LL calc_sum(LL n,LL m){
    LL res=0,w=1;
    while(w<=n){
        LL nxt=min(n/(n/w),m/(m/w));
        res+=(n/w)*(m/w)%MOD*(ask(nxt)-ask(w-1)+MOD)%MOD;
        res%=MOD;w=nxt+1;
    }return res;
}//整除分块求答案
int main(){
    Q=read();init();//预处理
    for(int i=1;i<=Q;i++){
        q[i].n=read(),q[i].m=read(),
        q[i].a=read(),q[i].id=i;
        if(q[i].n>q[i].m)swap(q[i].n,q[i].m);
    }//读入与存储
    sort(q+1,q+Q+1,cmp_q);//排序
    int now=1;//指针
    for(int i=1;i<=Q;i++){
        auto [id,n,m,ua]=q[i];
        while(now<=up&&s[now].val<=ua){
            LL x=s[now].x;
            for(LL k=x;k<=up;k+=x)
                upd(k,(sig[x]*mu[k/x]%MOD+MOD)%MOD);
            ++now;
        }//指针顺序遍历
        Ans[id]=calc_sum(n,m);//算出答案并存储（离线）
    }for(int i=1;i<=Q;i++)
        cout<<Ans[i]<<"\n";//输出
    return 0;
}
